import React from 'react';
import './Footer.css';

function Footer() {
  const year = new Date().getFullYear();
  return (
    <footer className="footer">
      <div className="container footer__inner">
        <a href="#hero" className="footer__logo">
          <span className="footer__bracket">&lt;</span>Alex<span className="footer__bracket"> /&gt;</span>
        </a>
        <p className="footer__copy">
          © {year} Alex Morgan. Designed &amp; built with{' '}
          <span className="footer__heart">♥</span> in Bangalore.
        </p>
        <a href="#hero" className="footer__back">Back to top ↑</a>
      </div>
    </footer>
  );
}

export default Footer;
